// AUTO-GENERATED from Dropbox/Cotto/dilution-calculator-shared.html — do not hand-edit.
export const CALCULATOR_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<title>Cotto · SAFE Dilution Calculator</title>\n<style>\n  :root{\n    --bg:#f7f4ef; --card:#fffdf9; --ink:#2b2722; --muted:#8a8378;\n    --line:#e7e0d4; --accent:#c0492f; --accent-soft:#f3d9d1;\n    --good:#3f7d56; --good-soft:#dcebe1; --shadow:0 1px 2px rgba(0,0,0,.04),0 8px 24px rgba(0,0,0,.05);\n  }\n  *{box-sizing:border-box}\n  body{margin:0;background:var(--bg);color:var(--ink);\n    font:15px/1.5 -apple-system,BlinkMacSystemFont,\"Segoe UI\",Roboto,Helvetica,Arial,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:28px 20px 80px}\n  .wrap{max-width:1060px;margin:0 auto}\n  h1{font-size:24px;margin:0 0 2px;letter-spacing:-.3px}\n  .sub{color:var(--muted);margin:0 0 22px;font-size:14px}\n  .grid2{display:grid;grid-template-columns:1fr 1fr;gap:16px}\n  @media(max-width:820px){.grid2{grid-template-columns:1fr}}\n  .card{background:var(--card);border:1px solid var(--line);border-radius:14px;\n    padding:18px 18px 16px;box-shadow:var(--shadow)}\n  .card h2{font-size:13px;text-transform:uppercase;letter-spacing:.6px;color:var(--muted);\n    margin:0 0 14px;font-weight:600}\n  label.ctl{display:block;margin-bottom:16px}\n  .ctl .row{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:6px}\n  .ctl .name{font-weight:600}\n  .ctl .val{font-variant-numeric:tabular-nums;font-weight:700;color:var(--accent);font-size:17px}\n  input[type=range]{width:100%;accent-color:var(--accent);height:22px}\n  .kpis{display:grid;grid-template-columns:1fr 1fr;gap:10px}\n  .kpi{background:var(--card);border:1px solid var(--line);border-radius:12px;padding:13px 14px}\n  .kpi .k{font-size:12px;color:var(--muted);margin-bottom:5px}\n  .kpi .v{font-size:26px;font-weight:750;font-variant-numeric:tabular-nums;letter-spacing:-.5px}\n  .kpi.accent .v{color:var(--accent)}\n  .kpi.good .v{color:var(--good)}\n  .kpi .vsub{font-size:12px;color:var(--muted);margin-top:3px}\n  .stack{display:grid;gap:13px}\n  /* cap table bar */\n  .bar{display:flex;height:30px;border-radius:8px;overflow:hidden;border:1px solid var(--line);margin:4px 0 10px}\n  .seg{display:flex;align-items:center;justify-content:center;color:#fff;font-size:11px;font-weight:600;\n    white-space:nowrap;overflow:hidden}\n  .lg{display:flex;flex-wrap:wrap;gap:10px 16px;font-size:12.5px}\n  .lg span{display:inline-flex;align-items:center;gap:6px}\n  .dot{width:10px;height:10px;border-radius:3px;display:inline-block}\n  table{width:100%;border-collapse:collapse;font-variant-numeric:tabular-nums;font-size:13px}\n  th,td{text-align:center;padding:7px 6px;border:1px solid var(--line)}\n  th{background:#f1ece3;font-weight:600;color:var(--muted);font-size:12px}\n  td.rowhead,th.rowhead{background:#f1ece3;font-weight:600;color:var(--ink);white-space:nowrap}\n  td.cell{cursor:pointer;transition:background .08s}\n  td.cell:hover{background:var(--accent-soft)}\n  td.sel{background:var(--accent);color:#fff;font-weight:700}\n  .toggle{display:inline-flex;border:1px solid var(--line);border-radius:9px;overflow:hidden;margin-bottom:12px}\n  .toggle button{border:0;background:var(--card);padding:7px 13px;font-size:12.5px;cursor:pointer;color:var(--muted);font-weight:600}\n  .toggle button.on{background:var(--accent);color:#fff}\n  .note{font-size:12.5px;color:var(--muted);margin-top:14px;line-height:1.6}\n  details{margin-top:14px;font-size:13px}\n  summary{cursor:pointer;color:var(--muted);font-weight:600}\n  .mini{display:grid;grid-template-columns:1fr auto;gap:6px 12px;margin-top:10px;max-width:360px}\n  .mini input{width:110px;text-align:right;border:1px solid var(--line);border-radius:7px;padding:5px 8px;font:inherit}\n  .heat0{background:#fbfaf7}.heat1{background:#f6ece6}.heat2{background:#eed7cb}.heat3{background:#e4bdab}.heat4{background:#d99e85}\n</style>\n</head>\n<body>\n<div class=\"wrap\">\n  <h1>Cotto · SAFE Dilution Calculator</h1>\n  <p class=\"sub\">How much we give away across new-raise amounts and SAFE caps. Post-money SAFEs, as-converted, no option pool.</p>\n\n  <div class=\"grid2\">\n    <!-- LEFT: controls -->\n    <div class=\"card\">\n      <h2>New raise</h2>\n      <label class=\"ctl\">\n        <div class=\"row\"><span class=\"name\">Amount raised</span><span class=\"val\" id=\"rLbl\">$650K</span></div>\n        <input type=\"range\" id=\"raise\" min=\"500000\" max=\"1000000\" step=\"50000\" value=\"650000\" />\n      </label>\n      <label class=\"ctl\">\n        <div class=\"row\"><span class=\"name\">SAFE cap (post-money)</span><span class=\"val\" id=\"cLbl\">$6.0M</span></div>\n        <input type=\"range\" id=\"cap\" min=\"5000000\" max=\"8000000\" step=\"500000\" value=\"6000000\" />\n      </label>\n\n      <div class=\"kpis\">\n        <div class=\"kpi accent\">\n          <div class=\"k\">Given away THIS round</div>\n          <div class=\"v\" id=\"kNew\">10.8%</div>\n          <div class=\"vsub\">to the new SAFE investors</div>\n        </div>\n        <div class=\"kpi good\">\n          <div class=\"k\">Founder stake after</div>\n          <div class=\"v\" id=\"kFounder\">80.8%</div>\n          <div class=\"vsub\" id=\"kFounderSub\">down from 91.7%</div>\n        </div>\n        <div class=\"kpi\">\n          <div class=\"k\">Founder total economic stake</div>\n          <div class=\"v\" id=\"kTotal\">82.5%</div>\n          <div class=\"vsub\">founder + founder's $50K SAFE</div>\n        </div>\n        <div class=\"kpi\">\n          <div class=\"k\">All outside investors</div>\n          <div class=\"v\" id=\"kOutside\">17.5%</div>\n          <div class=\"vsub\">F&amp;F + new round</div>\n        </div>\n      </div>\n    </div>\n\n    <!-- RIGHT: cap table -->\n    <div class=\"card\">\n      <h2>Resulting cap table</h2>\n      <div class=\"bar\" id=\"bar\"></div>\n      <div class=\"lg\" id=\"legend\"></div>\n      <div class=\"note\">\n        Post-money SAFEs lock each investor's % at signing. The F&amp;F investors stay at <b>6.67%</b> and the\n        founder's F&amp;F SAFE at <b>1.67%</b> no matter what's raised next — the new round's dilution comes out of\n        <b>founder common</b>. (A future priced round + option pool would dilute everyone.)\n      </div>\n    </div>\n  </div>\n\n  <!-- MATRIX -->\n  <div class=\"card\" style=\"margin-top:16px\">\n    <h2>Full grid — every raise × cap combination</h2>\n    <div class=\"toggle\" id=\"metricToggle\">\n      <button data-m=\"new\" class=\"on\">Given away this round</button>\n      <button data-m=\"founder\">Founder stake</button>\n      <button data-m=\"outside\">All outside investors</button>\n    </div>\n    <div style=\"overflow-x:auto\">\n      <table id=\"matrix\"></table>\n    </div>\n    <p class=\"note\">Rows = amount raised, columns = post-money cap. Click any cell to load it into the sliders above. Highlighted cell = current selection.</p>\n  </div>\n\n  <!-- ASSUMPTIONS -->\n  <div class=\"card\" style=\"margin-top:16px\">\n    <details open>\n      <summary>Existing round &amp; assumptions (editable)</summary>\n      <div class=\"mini\">\n        <span>F&amp;F SAFE — outside investors ($)</span><input type=\"number\" id=\"ffOutside\" value=\"200000\" />\n        <span>F&amp;F SAFE — founder's money ($)</span><input type=\"number\" id=\"ffSelf\" value=\"50000\" />\n        <span>F&amp;F post-money cap ($)</span><input type=\"number\" id=\"ffCap\" value=\"3000000\" />\n      </div>\n      <p class=\"note\">\n        Prior round: <b>$250K friends-and-family SAFE</b> at a <b>$3M post-money cap</b> — $200K from outside F&amp;F\n        investors plus $50K from the founder. Mechanics: this models <b>post-money SAFEs as-converted</b> (treated as\n        if already equity), which is how to think about ownership even though dilution isn't legally \"realized\" until a\n        priced round. Each new SAFE investor's ownership = <b>amount ÷ cap</b>. No option pool is modeled — adding a\n        standard 10% pool at the next priced round would reduce the founder stake by roughly another 10 points and\n        dilute everyone proportionally. Not financial or legal advice; sanity-check against the actual SAFE docs.\n      </p>\n    </details>\n  </div>\n</div>\n\n<script>\nconst $ = id => document.getElementById(id);\nconst fmtMoney = n => n>=1e6 ? '$'+(n/1e6).toFixed(n%1e6?1:0)+'M' : '$'+Math.round(n/1000)+'K';\nconst pct = x => (x*100).toFixed(1)+'%';\n\nlet metric = 'new';\n\nfunction ff(){\n  const outside = +$('ffOutside').value, self = +$('ffSelf').value, cap = +$('ffCap').value;\n  return {outside: outside/cap, self: self/cap, total:(outside+self)/cap};\n}\n\n// core math for a given raise & cap\nfunction calc(raise, cap){\n  const f = ff();\n  const newPct = raise/cap;                       // given away this round\n  const founder = 1 - f.total - newPct;           // founder common\n  const youTotal = founder + f.self;              // founder + founder's safe\n  const outside = f.outside + newPct;             // F&F + new investors\n  return {newPct, founder, youTotal, outside, ff:f};\n}\n\nfunction render(){\n  const raise = +$('raise').value, cap = +$('cap').value;\n  $('rLbl').textContent = fmtMoney(raise);\n  $('cLbl').textContent = '$'+(cap/1e6).toFixed(1)+'M';\n  const r = calc(raise, cap);\n\n  $('kNew').textContent = pct(r.newPct);\n  $('kFounder').textContent = pct(r.founder);\n  $('kFounderSub').textContent = 'down from '+pct(1 - r.ff.total);\n  $('kTotal').textContent = pct(r.youTotal);\n  $('kOutside').textContent = pct(r.outside);\n\n  // bar segments: founder, founder safe, F&F, new\n  const segs = [\n    {label:'Founder', v:r.founder, c:'#3f7d56'},\n    {label:'Founder SAFE', v:r.ff.self, c:'#7fb08e'},\n    {label:'F&F investors', v:r.ff.outside, c:'#d99e85'},\n    {label:'New round', v:r.newPct, c:'#c0492f'},\n  ];\n  $('bar').innerHTML = segs.map(s=>\n    `<div class=\"seg\" style=\"width:${(s.v*100).toFixed(2)}%;background:${s.c}\">${s.v>0.06?pct(s.v):''}</div>`).join('');\n  $('legend').innerHTML = segs.map(s=>\n    `<span><span class=\"dot\" style=\"background:${s.c}\"></span>${s.label} · ${pct(s.v)}</span>`).join('');\n\n  buildMatrix(raise, cap);\n}\n\nconst RAISES = [];\nfor(let v=500000; v<=1000000; v+=50000) RAISES.push(v);\nconst CAPS = [];\nfor(let v=5000000; v<=8000000; v+=500000) CAPS.push(v);\n\nfunction metricVal(c){\n  if(metric==='new') return c.newPct;\n  if(metric==='founder') return c.founder;\n  return c.outside;\n}\nfunction heat(x){\n  // relative heat for \"given away\" feel: more = hotter for new/outside, inverse for founder\n  let t = metric==='founder' ? (1-x) : x;\n  // normalize roughly 0.06–0.22 band\n  t = Math.max(0, Math.min(1, (t-0.06)/(0.20)));\n  return 'heat'+Math.min(4, Math.floor(t*5));\n}\n\nfunction buildMatrix(curRaise, curCap){\n  let html = '<tr><th class=\"rowhead\">Raise ＼ Cap</th>';\n  CAPS.forEach(c=> html += `<th>$${(c/1e6).toFixed(1)}M</th>`);\n  html += '</tr>';\n  RAISES.forEach(R=>{\n    html += `<tr><td class=\"rowhead\">${fmtMoney(R)}</td>`;\n    CAPS.forEach(C=>{\n      const c = calc(R,C);\n      const v = metricVal(c);\n      const sel = (R===curRaise && C===curCap) ? ' sel' : ' '+heat(v);\n      html += `<td class=\"cell${sel}\" data-r=\"${R}\" data-c=\"${C}\">${pct(v)}</td>`;\n    });\n    html += '</tr>';\n  });\n  const t = $('matrix');\n  t.innerHTML = html;\n  t.querySelectorAll('td.cell').forEach(td=>{\n    td.onclick = ()=>{ $('raise').value=td.dataset.r; $('cap').value=td.dataset.c; render(); };\n  });\n}\n\n['raise','cap','ffOutside','ffSelf','ffCap'].forEach(id=> $(id).addEventListener('input', render));\n$('metricToggle').querySelectorAll('button').forEach(b=>{\n  b.onclick = ()=>{\n    metric = b.dataset.m;\n    $('metricToggle').querySelectorAll('button').forEach(x=>x.classList.remove('on'));\n    b.classList.add('on');\n    render();\n  };\n});\n\nrender();\n</script>\n</body>\n</html>\n";
